/// <summary>
/// Resolves the date range for Insights v2.0.6 endpoints (/summary, /trends, /errors/top).
/// Enforces the v2.0.6 §3.3 contract verbatim:
///   startTime: ISO-8601 date-time, ≥ now − 60d, ≤ endTime, default = now − 7d.
///   endTime:   ISO-8601 date-time, &gt; startTime, ≤ now, window ≤ 60d, default = now.
/// Defaults are applied independently when a side is omitted.
/// Comparisons run at full DateTimeOffset instant precision; the SQL layer is day-bucketed
/// (results in yyyy-MM-dd UTC) so same-day windows are honored at day resolution.
/// </summary>

var now = DateTimeOffset.UtcNow;
var start = startTime ?? now.AddDays(-DefaultDateRangeDays);
var end = endTime ?? now;

if (start < now.AddDays(-MaxStrictDateRangeDays))
{
    return (null, null, BadRequest(new { error = $"startTime must be within the last {MaxStrictDateRangeDays} days." }));
}

if (end > now)
{
    return (null, null, BadRequest(new { error = "endTime cannot be in the future." }));
}

if (end <= start)
{
    return (null, null, BadRequest(new { error = "endTime must be after startTime." }));
}

if ((end - start) > TimeSpan.FromDays(MaxStrictDateRangeDays))
{
    return (null, null, BadRequest(new { error = $"Date range must not exceed {MaxStrictDateRangeDays} days." }));
}

var startStr = start.UtcDateTime.ToString("yyyy-MM-dd", System.Globalization.CultureInfo.InvariantCulture);
var endStr = end.UtcDateTime.ToString("yyyy-MM-dd", System.Globalization.CultureInfo.InvariantCulture);
return (startStr, endStr, null);

